import * as XLSX from "xlsx"

// アップロードされたファイルを解析
export async function readExcel(file) {
    return new Promise((resolve, reject) => {
        const reader = new FileReader()
        reader.readAsArrayBuffer(file)
        reader.onload = (e) => {
            try {
                const data = new Uint8Array(e.target.result)
                const workbook = XLSX.read(data, { type: "array" })

                // 最初のシートを取得
                const sheet = workbook.Sheets[workbook.SheetNames[0]]
                const json = XLSX.utils.sheet_to_json(sheet, { header: 1 })

                // JSONデータを整形
                const subtitles = {}
                json.slice(1).forEach(row => {
                    const time = row[0]?.toString().trim()
                    const subtitle = row[1]?.toString().trim()
                    const translation = row[2]?.toString().trim()

                    if (time) {
                        subtitles[time] = { subtitle, translation }
                    }
                })

                resolve(subtitles)
            } catch (error) {
                reject(error)
            }
        }
        reader.onerror = (error) => reject(error)
    })
}


// LocalStorageのvideoDataListを取得
export const getVideoDataList = () => {
    const videoDataList = window.localStorage.getItem("videoDataList")
    if (videoDataList) {
        return JSON.parse(videoDataList)
    }

    // 存在しない場合は、空配列を返却
    return []
}

// LocalStorageにvideoIdの保存
export const setVideoId = async () => {
    // 入力されたvideoIdを取得
    const videoId = document.getElementById("input-videoId").value
    // アップロードされた翻訳字幕データを取得、なければ空配列
    const subtitles = document.getElementById("upload").files[0] ? await readExcel(document.getElementById("upload").files[0]) : null

    // 動画データの初期化
    const subtitlesData = {
        videoId: videoId,
        subtitles: subtitles
    }

    // 保存済みの動画データを取得し、追記
    const videoDataList = getVideoDataList()
    videoDataList.push(subtitlesData)

    // 保存
    window.localStorage.setItem("videoDataList", JSON.stringify(videoDataList))
}

