import React, { useState } from "react";

import { Dialog, Grid2, IconButton, Box, Typography } from "@mui/material";
import CloseIcon from '@mui/icons-material/Close';
import ReactPlayer from 'react-player/lazy'

function formatTime(seconds) {
    const hour = Math.floor(seconds / 3600);
    const min = Math.floor(seconds % 3600 / 60);
    const sec = Math.floor(seconds % 60)

    if (hour !== 0) {
        return `${hour}:${min.toString().padStart(2, '0')}:${sec.toString().padStart(2, '0')}`
    } else if (min !== 0) {
        return `${min}:${sec.toString().padStart(2, '0')}`
    } else {
        return `${sec.toString()}s`
    }
}

function Player({ open, onClose, video }) {
    // const [displaySubtitles, setDisplaySubtitles] = useState(false)
    const [subtitle, setSubtitle] = useState("")
    const [translation, setTranslation] = useState("")

    function handleOnPlay() {
        console.log("onPlay")
        // setDisplaySubtitles(true)
    }

    function handleOnPause() {
        console.log("onPause")
        // setDisplaySubtitles(false)
    }

    function handleProgress(state) {
        const formattedTime = formatTime(state.playedSeconds)
        if (video?.subtitles[formattedTime] !== undefined) {
            console.log(video?.subtitles[formattedTime].subtitle)
            console.log(video?.subtitles[formattedTime].translation)
            setSubtitle(video?.subtitles[formattedTime].subtitle)
            setTranslation(video?.subtitles[formattedTime].translation)
        }
    }

    return (
        <Dialog
            fullScreen
            open={open}
            onClose={onClose}
        >
            <Box>
                <Grid2
                    container
                    direction="row"
                    sx={{
                        justifyContent: "space-between",
                        alignItems: "center"
                    }}
                >
                    <Box></Box>
                    <IconButton
                        edge="start"
                        color="inherit"
                        onClick={onClose}
                        aria-label="close"
                    >
                        <CloseIcon />
                    </IconButton>
                </Grid2>
            </Box>

            <Box sx={{ position: "relative", width: "100%", maxHeight: "100vh", aspectRatio: "16 / 9" }}>
                <ReactPlayer
                    url={`https://youtu.be/${video?.videoId}`}
                    width={"100%"}
                    height={"100%"}
                    controls={true}
                    onPlay={handleOnPlay}
                    onPause={handleOnPause}
                    onProgress={handleProgress}
                />
                <Box sx={{ position: 'absolute', bottom: "12%", width: "100%", textAlign: "center", textShadow: "2px 2px 4px rgba(0, 0, 0, 0.8)", background: "rgba(0, 0, 0, 0.5)", color: "white", paddingY: 1 }}>
                    <Typography>test{subtitle}</Typography>
                    <Typography>{translation}</Typography>
                </Box>


            </Box>

        </Dialog >
    );
}

export default Player;
